pragma solidity ^0.8.20;

contract Payouts {
    // Preferred: pull payment pattern. Do NOT push ether to many
    // recipients in a loop; let each recipient withdraw their share.
    mapping(address => uint256) public owed;

    function creditWinners(address[] calldata winners, uint256 share) internal {
        for (uint256 i = 0; i < winners.length; i++) {
            owed[winners[i]] += share; // storage write only, no external call
        }
    }

    function withdraw() external {
        uint256 amount = owed[msg.sender];
        owed[msg.sender] = 0;
        (bool ok, ) = payable(msg.sender).call{value: amount}("");
        require(ok, "withdraw failed");
    }

    // If iteration is unavoidable, bound it and make it resumable:
    uint256 public constant MAX_BATCH = 50;
    uint256 public cursor;
    address[] public recipients;

    function processBatch() external {
        uint256 end = cursor + MAX_BATCH;
        if (end > recipients.length) end = recipients.length;
        for (uint256 i = cursor; i < end; i++) {
            // process recipients[i]; a failure should be recorded,
            // not allowed to revert the whole batch
        }
        cursor = end; // resume from here in the next transaction
    }
}
